    template_code = 'about_company',
    content_json = '{"hero":{"title":"Ve Chung Toi","backgroundImagePath":""},"intro":{"heading":"Doi tac tin cay trong nganh khao sat xay dung","content":"<p>Hanoi Survey duoc thanh lap voi dinh huong cung cap giai phap khao sat, thi nghiem va quan trac chinh xac cho cac du an dan dung, cong nghiep va ha tang ky thuat tren toan quoc.</p><p>Chung toi ket hop kinh nghiem thuc dia, quy trinh van hanh ro rang va he thong thiet bi hien dai de giup chu dau tu, tu van thiet ke va tong thau co du lieu ky thuat dang tin cay ngay tu giai doan dau cua du an.</p>"},"coreValues":{"sectionTitle":"Su Menh va Tam Nhin","items":[{"title":"Su Menh","icon":"bullseye","description":"Cung cap du lieu khao sat va thi nghiem chinh xac, minh bach, giup toi uu giai phap nen mong va giam thieu rui ro ky thuat cho moi cong trinh."},{"title":"Tam Nhin","icon":"eye","description":"Tro thanh don vi khao sat va quan trac duoc uu tien lua chon trong cac du an ha tang, cong nghiep va phat trien do thi tai Viet Nam."},{"title":"Gia Tri Cot Loi","icon":"gem","description":"Chinh xac - Uy tin - Tan tam. Chung toi coi chat luong du lieu, toc do phoi hop va trach nhiem nghe nghiep la nen tang cua moi du an."}]},"timeline":{"sectionTitle":"Qua Trinh Phat Trien","items":[{"year":"2013","title":"Thanh lap doanh nghiep","description":"Khoi dau voi doi ngu ky su nen mong va khao sat, tap trung phuc vu cac cong trinh dan dung va nha xuong quy mo vua tai mien Bac.","sortOrder":1},{"year":"2016","title":"Mo rong nang luc thi cong","description":"Dau tu bo sung may khoan, thiet bi do dac va mo rong doi hien truong de dap ung nhieu du an song song.","sortOrder":2},{"year":"2019","title":"Chuan hoa quy trinh","description":"Hoan thien he thong quan ly chat luong, nang cap quy trinh trien khai va tang cuong nang luc bao cao ky thuat.","sortOrder":3},{"year":"2023 - Nay","title":"Tang truong ben vung","description":"Tham gia nhieu du an trong diem ve giao thong, cong nghiep va phat trien do thi voi goi dich vu khao sat tron goi.","sortOrder":4}]},"organization":{"sectionTitle":"Co Cau To Chuc","heading":"To chuc khoa hoc de trien khai nhanh va kiem soat chat luong","description":"Mo hinh van hanh duoc phan tach ro giua khoi dieu hanh, khoi ky thuat va cac doi hien truong, giup doanh nghiep duy tri tien do, bao dam chat luong du lieu va tang kha nang phoi hop tren cong truong.","chartImagePath":"","chartCaption":"So do to chuc nhan su","departments":["Ban Giam doc va Hoi dong quan tri","Phong Ky thuat - Nghien cuu va Phat trien","Phong Thi nghiem va Kiem dinh chat luong","Phong Thiet ke va Xay lap","Phong Hanh chinh - Nhan su va Ke toan","Cac doi thi cong hien truong"]},"capability":{"sectionTitle":"Ho So Nang Luc","heading":"Nang luc va chung chi cua chung toi","description":"Chung toi duy tri day du ho so phap ly, nang luc hanh nghe va cac tai lieu ky thuat can thiet de tham gia nhieu loai hinh du an tu dan dung den ha tang ky thuat.","imagePath":"","items":[{"title":"Giay phep dang ky kinh doanh","pdfFilePath":"","buttonLabel":"Xem PDF"},{"title":"Chung chi nang luc hoat dong khao sat xay dung","pdfFilePath":"","buttonLabel":"Xem PDF"},{"title":"Chung nhan he thong quan ly chat luong","pdfFilePath":"","buttonLabel":"Xem PDF"},{"title":"Ho so kinh nghiem cac du an tieu bieu","pdfFilePath":"","buttonLabel":"Xem PDF"}]}}'
